/**
 * Returns the most recently scored wallets in this session, sorted by
most recent first. Used to power the live activity feed.

 * @summary Recent wallet checks
 */
export const getGetRecentChecksUrl = (params?: GetRecentChecksParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/wallet/leaderboard?${stringifiedParams}`
    : `/api/wallet/leaderboard`;
};

